85: // New creates a new etcdv3 client from a given configuration.
86: func New(cfg Config) (*Client, error) {
87: 	if len(cfg.Endpoints) == 0 {
88: 		return nil, ErrNoAvailableEndpoints
89: 	}
90: 
91: 	return newClient(&cfg)
92: }
93: 
94: // NewCtxClient creates a client with a context but no underlying grpc
95: // connection. This is useful for embedded cases that override the
96: // service interface implementations and do not need connection management.
97: func NewCtxClient(ctx context.Context, opts ...Option) *Client {
98: 	cctx, cancel := context.WithCancel(ctx)
99: 	c := &Client{ctx: cctx, cancel: cancel, epMu: new(sync.RWMutex)}
100: 	for _, opt := range opts {
101: 		opt(c)
102: 	}
103: 	if c.lg.Load() == nil {
104: 		c.lg.Store(zap.NewNop())
105: 	}
106: 	return c
107: }
108: 
109: // Option is a function type that can be passed as argument to NewCtxClient to configure client
110: type Option func(*Client)
111: 
112: // NewFromURL creates a new etcdv3 client from a URL.
113: func NewFromURL(url string) (*Client, error) {
114: 	return New(Config{Endpoints: []string{url}})
115: }
