146: // Close shuts down the client's etcd connections.
147: func (c *Client) Close() error {
148: 	c.cancel()
149: 	if c.Watcher != nil {
150: 		c.Watcher.Close()
151: 	}
152: 	if c.Lease != nil {
153: 		c.Lease.Close()
154: 	}
155: 	if c.conn != nil {
156: 		return ContextError(c.ctx, c.conn.Close())
157: 	}
158: 	return c.ctx.Err()
159: }
