166: // Endpoints lists the registered endpoints for the client.
167: func (c *Client) Endpoints() []string {
168: 	// copy the slice; protect original endpoints from being changed
169: 	c.epMu.RLock()
170: 	defer c.epMu.RUnlock()
171: 	eps := make([]string, len(c.endpoints))
172: 	copy(eps, c.endpoints)
173: 	return eps
174: }
175: 
176: // SetEndpoints updates client's endpoints.
177: func (c *Client) SetEndpoints(eps ...string) {
178: 	c.epMu.Lock()
179: 	defer c.epMu.Unlock()
180: 	c.endpoints = eps
181: 
182: 	c.resolver.SetEndpoints(eps)
183: }
