185: // Sync synchronizes client's endpoints with the known endpoints from the etcd membership.
186: func (c *Client) Sync(ctx context.Context) error {
187: 	mresp, err := c.MemberList(ctx)
188: 	if err != nil {
189: 		return err
190: 	}
191: 	var eps []string
192: 	for _, m := range mresp.Members {
193: 		if len(m.Name) != 0 && !m.IsLearner {
194: 			eps = append(eps, m.ClientURLs...)
195: 		}
196: 	}
197: 	// The linearizable `MemberList` returned successfully, so the
198: 	// endpoints shouldn't be empty.
199: 	verify.Verify("empty endpoints returned from etcd cluster", func() (bool, map[string]any) {
200: 		return len(eps) > 0, nil
201: 	})
202: 	c.SetEndpoints(eps...)
203: 	c.GetLogger().Debug("set etcd endpoints by autoSync", zap.Strings("endpoints", eps))
204: 	return nil
205: }
206: 
207: func (c *Client) autoSync() {
208: 	if c.cfg.AutoSyncInterval == time.Duration(0) {
209: 		return
210: 	}
211: 
212: 	for {
213: 		select {
214: 		case <-c.ctx.Done():
215: 			return
216: 		case <-time.After(c.cfg.AutoSyncInterval):
217: 			ctx, cancel := context.WithTimeout(c.ctx, 5*time.Second)
218: 			err := c.Sync(ctx)
219: 			cancel()
220: 			if err != nil && !errors.Is(err, c.ctx.Err()) {
221: 				c.GetLogger().Info("Auto sync endpoints failed.", zap.Error(err))
222: 			}
223: 		}
224: 	}
225: }
