276: // Dial connects to a single endpoint using the client's config.
277: func (c *Client) Dial(ep string) (*grpc.ClientConn, error) {
278: 	creds := c.credentialsForEndpoint(ep)
279: 
280: 	// Using ad-hoc created resolver, to guarantee only explicitly given
281: 	// endpoint is used.
282: 	return c.dial(creds, grpc.WithResolvers(resolver.New(ep)))
283: }
