285: func (c *Client) getToken(ctx context.Context) error {
286: 	var err error // return last error in a case of fail
287: 
288: 	if c.Token != "" {
289: 		c.authTokenBundle.UpdateAuthToken(c.Token)
290: 		return nil
291: 	}
292: 
293: 	if c.Username == "" || c.Password == "" {
294: 		return nil
295: 	}
296: 
297: 	resp, err := c.Auth.Authenticate(ctx, c.Username, c.Password)
298: 	if err != nil {
299: 		if errors.Is(err, rpctypes.ErrAuthNotEnabled) {
300: 			c.authTokenBundle.UpdateAuthToken("")
301: 			return nil
302: 		}
303: 		return err
304: 	}
305: 	c.authTokenBundle.UpdateAuthToken(resp.Token)
306: 	return nil
307: }
