614: // ContextError converts the error into an EtcdError if the error message matches one of
615: // the defined messages; otherwise, it tries to retrieve the context error.
616: func ContextError(ctx context.Context, err error) error {
617: 	if err == nil {
618: 		return nil
619: 	}
620: 	err = rpctypes.Error(err)
621: 	var serverErr rpctypes.EtcdError
622: 	if errors.As(err, &serverErr) {
623: 		return err
624: 	}
625: 	if ev, ok := status.FromError(err); ok {
626: 		code := ev.Code()
627: 		switch code {
628: 		case codes.DeadlineExceeded:
629: 			fallthrough
630: 		case codes.Canceled:
631: 			if ctx.Err() != nil {
632: 				err = ctx.Err()
633: 			}
634: 		}
635: 	}
636: 	return err
637: }
