639: func canceledByCaller(stopCtx context.Context, err error) bool {
640: 	if stopCtx.Err() == nil || err == nil {
641: 		return false
642: 	}
643: 
644: 	return errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)
645: }
