647: // IsConnCanceled returns true, if error is from a closed gRPC connection.
648: // ref. https://github.com/grpc/grpc-go/pull/1854
649: func IsConnCanceled(err error) bool {
650: 	if err == nil {
651: 		return false
652: 	}
653: 
654: 	// >= gRPC v1.23.x
655: 	s, ok := status.FromError(err)
656: 	if ok {
657: 		// connection is canceled or server has already closed the connection
658: 		return s.Code() == codes.Canceled || s.Message() == "transport is closing"
659: 	}
660: 
661: 	// >= gRPC v1.10.x
662: 	if errors.Is(err, context.Canceled) {
663: 		return true
664: 	}
665: 
666: 	// <= gRPC v1.7.x returns 'errors.New("grpc: the client connection is closing")'
667: 	return strings.Contains(err.Error(), "grpc: the client connection is closing")
668: }
