588: func (c *csiDriverClient) NodeGetVolumeStats(ctx context.Context, volID string, targetPath string) (*volume.Metrics, error) {
589: 	klog.V(4).InfoS(log("calling NodeGetVolumeStats rpc"), "volID", volID, "targetPath", targetPath)
590: 	if volID == "" {
591: 		return nil, errors.New("missing volume id")
592: 	}
593: 	if targetPath == "" {
594: 		return nil, errors.New("missing target path")
595: 	}
596: 	if c.nodeV1ClientCreator == nil {
597: 		return nil, errors.New("nodeV1ClientCreate is nil")
598: 	}
599: 
600: 	nodeClient, closer, err := c.nodeV1ClientCreator(c.addr, c.metricsManager)
601: 	if err != nil {
602: 		return nil, err
603: 	}
604: 	defer closer.Close()
605: 
606: 	req := &csipbv1.NodeGetVolumeStatsRequest{
607: 		VolumeId:   volID,
608: 		VolumePath: targetPath,
609: 	}
610: 
611: 	resp, err := nodeClient.NodeGetVolumeStats(ctx, req)
612: 	if err != nil {
613: 		return nil, err
614: 	}
615: 
616: 	metrics := &volume.Metrics{
617: 		Used:       resource.NewQuantity(int64(0), resource.BinarySI),
618: 		Capacity:   resource.NewQuantity(int64(0), resource.BinarySI),
619: 		Available:  resource.NewQuantity(int64(0), resource.BinarySI),
620: 		InodesUsed: resource.NewQuantity(int64(0), resource.BinarySI),
621: 		Inodes:     resource.NewQuantity(int64(0), resource.BinarySI),
622: 		InodesFree: resource.NewQuantity(int64(0), resource.BinarySI),
623: 	}
624: 
625: 	var isSupportNodeVolumeCondition bool
626: 	if utilfeature.DefaultFeatureGate.Enabled(features.CSIVolumeHealth) {
627: 		isSupportNodeVolumeCondition, err = c.nodeSupportsVolumeCondition(ctx)
628: 		if err != nil {
629: 			return nil, err
630: 		}
631: 
632: 		if isSupportNodeVolumeCondition {
633: 			abnormal, message := resp.VolumeCondition.GetAbnormal(), resp.VolumeCondition.GetMessage()
634: 			metrics.Abnormal, metrics.Message = &abnormal, &message
635: 		}
636: 	}
637: 
638: 	usages := resp.GetUsage()
639: 	// If the driver does not support volume condition and usages is nil, return an error
640: 	if !isSupportNodeVolumeCondition && usages == nil {
641: 		return nil, fmt.Errorf("failed to get usage from response. usage is nil")
642: 	}
643: 
644: 	for _, usage := range usages {
645: 		if usage == nil {
646: 			continue
647: 		}
648: 		unit := usage.GetUnit()
649: 		switch unit {
650: 		case csipbv1.VolumeUsage_BYTES:
651: 			metrics.Available = resource.NewQuantity(usage.GetAvailable(), resource.BinarySI)
652: 			metrics.Capacity = resource.NewQuantity(usage.GetTotal(), resource.BinarySI)
653: 			metrics.Used = resource.NewQuantity(usage.GetUsed(), resource.BinarySI)
654: 		case csipbv1.VolumeUsage_INODES:
655: 			metrics.InodesFree = resource.NewQuantity(usage.GetAvailable(), resource.BinarySI)
656: 			metrics.Inodes = resource.NewQuantity(usage.GetTotal(), resource.BinarySI)
657: 			metrics.InodesUsed = resource.NewQuantity(usage.GetUsed(), resource.BinarySI)
658: 		default:
659: 			klog.ErrorS(nil, "unknown unit in VolumeUsage", "unit", unit.String())
660: 		}
661: 
662: 	}
663: 	return metrics, nil
664: }
