693: 	if c.nodeV1ClientCreator == nil {
694: 		return []*csipbv1.NodeServiceCapability{}, errors.New("nodeV1ClientCreate is nil")
695: 	}
696: 
697: 	nodeClient, closer, err := c.nodeV1ClientCreator(c.addr, c.metricsManager)
698: 	if err != nil {
699: 		return []*csipbv1.NodeServiceCapability{}, err
700: 	}
701: 	defer closer.Close()
702: 
703: 	req := &csipbv1.NodeGetCapabilitiesRequest{}
704: 	resp, err := nodeClient.NodeGetCapabilities(ctx, req)
705: 	if err != nil {
706: 		if !isFinalError(err) {
707: 			return []*csipbv1.NodeServiceCapability{}, volumetypes.NewUncertainProgressError(err.Error())
708: 		}
709: 		return []*csipbv1.NodeServiceCapability{}, err
710: 	}
711: 	return resp.GetCapabilities(), nil
